399	func decodeCanonicalReadinessPayloadWithMode(payload string, qualityMode string) (PreClaimIntakeResult, error) {
400		var out preClaimReadinessPromptResult
401		if err := json.Unmarshal([]byte(payload), &out); err != nil {
402			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode readiness result: %w", err)
403		}
404		detail := strings.TrimSpace(out.Reason)
405		if detail == "" {
406			detail = strings.TrimSpace(out.Detail)
407		}
408		rewrite := PreClaimIntakeRewrite{
409			Description:   strings.TrimSpace(out.Rewrite.Description),
410			Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
411			ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
412		}
413		switch strings.ToLower(strings.TrimSpace(out.Outcome)) {
414		case "actionable_atomic":
415			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic, Detail: detail}, nil
416		case "actionable_but_rewritten":
417			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableButRewritten, Detail: detail, Rewrite: rewrite}, nil
418		case "too_large_decomposed":
419			return PreClaimIntakeResult{Outcome: PreClaimIntakeTooLargeDecomposed, Reason: ReadinessReasonTooLarge, Detail: detail}, nil
420		case "operator_required", "human_review_required":
421			return PreClaimIntakeResult{Outcome: PreClaimIntakeOperatorRequired, Reason: ReadinessReasonAmbiguousScope, Detail: detail}, nil
422		case "ambiguous_needs_human", "needs_human":
423			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: legacy readiness outcome %q removed by lifecycle migration; use %q", out.Outcome, PreClaimIntakeOperatorRequired)
424		case "readiness_error", "system_unready":
425			// system_unready maps to fail-open/skip per ADR-023/FEAT-010 policy
426			classified := ClassifyReadinessWithMode(ReadinessClassificationSystemUnready, nil, detail, qualityMode)
427			return PreClaimIntakeResult{
428				Outcome:      PreClaimIntakeError,
429				Reason:       classified.Reason,
430				SystemReason: classified.SystemReason,
431				Detail:       detail,
432			}, nil
433		case "":
434			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing outcome")
435		default:
436			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: unknown readiness outcome %q: expected one of actionable_atomic, actionable_but_rewritten, too_large_decomposed, operator_required, readiness_error, system_unready", out.Outcome)
437		}
